const GEMINI_TTS_MODEL = "gemini-2.5-flash-preview-tts";
let currentVoiceIdx = parseInt(localStorage.getItem("puter_voice_idx")||"0");

async function speak(text) {
  if (!window.puter) return;
  const v = PUTER_VOICES[currentVoiceIdx] || PUTER_VOICES[0];
  try {
    const audio = await window.puter.ai.txt2speech(text, {
      provider: "gemini",
      model: GEMINI_TTS_MODEL,
      voice: v.voice,
      instructions: v.instructions,
    });
    audio.play();
  } catch(e) { console.warn("Puter Gemini TTS error:", e); }
}

function extractReadableText(text) {
  if (!text) return "";
  // HTML 태그 제거, 마크다운 기호 정리
  return text
    .replace(/\*\*/g, "")
    .replace(/【[^】]*】/g, "")          // 단계 태그 제거
    .replace(/\|[^\n]+\|/g, "")         // 테이블 행 제거
    .replace(/[-]{3,}/g, "")
    .replace(/<[^>]+>/g, "")
    .replace(/\n{3,}/g, "\n\n")
    .trim()
    .slice(0, 800);                     // 너무 긴 경우 앞 800자만
}

/* ── Typing dots ── */
function Dots() {
  return (
    <div style={{display:"flex",alignItems:"center",gap:5,padding:"12px 16px"}}>
      {[0,1,2].map(i=>(
        <div key={i} style={{
          width:8,height:8,borderRadius:"50%",background:"#a78bfa",
          animation:`bounce 1.2s ease-in-out ${i*0.2}s infinite`
        }}/>
      ))}
    </div>
  );
}

/* ── Message bubble ── */
function Bubble({ msg, onContinue }) {
  const isUser = msg.role === "user";
  const engText = !isUser ? extractReadableText(msg.content) : "";
  const [speaking, setSpeaking] = useState(false);
  const handleSpeak = async () => {
    if(speaking) return;
    setSpeaking(true);
    await speak(engText);
    setSpeaking(false);
  };
  return (
    <div style={{
      display:"flex",flexDirection:isUser?"row-reverse":"row",
      alignItems:"flex-end",gap:10,marginBottom:16,
      animation:"fadeIn 0.3s ease-out",
    }}>
      {!isUser && (
        <div style={{
          width:36,height:36,borderRadius:"50%",flexShrink:0,
          background:"linear-gradient(135deg,#7c3aed,#a78bfa)",
          display:"flex",alignItems:"center",justifyContent:"center",fontSize:16,
          boxShadow:"0 0 12px rgba(167,139,250,0.4)",
        }}>🌸</div>
      )}
      <div style={{maxWidth:"78%",position:"relative"}}>
        <div style={{
          background: isUser?"linear-gradient(135deg,#7c3aed,#6d28d9)":"rgba(255,255,255,0.06)",
          border: isUser?"none":"1px solid rgba(167,139,250,0.2)",
          borderRadius: isUser?"18px 18px 4px 18px":"18px 18px 18px 4px",
          padding:"12px 16px",color:"#f1f0ff",fontSize:14,lineHeight:1.7,
          backdropFilter:"blur(10px)",
          boxShadow: isUser?"0 4px 20px rgba(124,58,237,0.3)":"0 2px 12px rgba(0,0,0,0.2)",
        }}>
          {msg.imagePreview && (
            <img src={msg.imagePreview} alt="upload"
              style={{width:"100%",borderRadius:10,marginBottom:8,maxHeight:180,objectFit:"cover"}}/>
          )}
          <div dangerouslySetInnerHTML={{__html: md(msg.content)}}/>
        </div>
        <div style={{display:"flex",gap:6,flexWrap:"wrap"}}>
          {!isUser && engText && (
            <button
              onClick={handleSpeak}
              disabled={speaking}
              style={{
                marginTop:6,marginLeft:4,
                background: speaking ? "rgba(167,139,250,0.3)" : "rgba(167,139,250,0.15)",
                border:"1px solid rgba(167,139,250,0.3)",
                borderRadius:20,color:"#c4b5fd",fontSize:11,
                padding:"4px 12px",cursor: speaking ? "default" : "pointer",
                display:"flex",alignItems:"center",gap:5,
              }}
            >{speaking ? "⏳ 재생 중..." : "🔊 낭독"}</button>
          )}
          {!isUser && msg.cutOff && onContinue && (
            <button
              onClick={onContinue}
              style={{
                marginTop:6,
                background:"rgba(245,158,11,0.2)",
                border:"1px solid rgba(245,158,11,0.4)",
                borderRadius:20,color:"#fcd34d",fontSize:11,
                padding:"4px 12px",cursor:"pointer",
                display:"flex",alignItems:"center",gap:5,
              }}
            >➡️ 이어서 계속</button>
          )}
        </div>
      </div>
    </div>
  );
}

/* ── Main App ── */
export default function App() {
  const [msgs, setMsgs] = useState([WELCOME]);
  const [input, setInput] = useState("");
  const [loading, setLoading] = useState(false);
  const [pendingImg, setPendingImg] = useState(null);
  const [pendingPrev, setPendingPrev] = useState(null);
  const [storedImg, setStoredImg] = useState(null);
  const [apiKey, setApiKey] = useState(() => localStorage.getItem("gemini_key") || "");
  const [showKey, setShowKey] = useState(false);
  const [showVoice, setShowVoice] = useState(false);
  const [selVoiceIdx, setSelVoiceIdx] = useState(currentVoiceIdx);
  const [puterReady, setPuterReady] = useState(!!window.puter);
  const [ttsLoading, setTtsLoading] = useState(false);
  const [convMode, setConvMode] = useState(false); // 4단계 회화 모드
  const [listening, setListening] = useState(false);
  const recogRef = useRef(null);
  const bottomRef = useRef(null);
  const inputRef = useRef(null);
  const fileRef = useRef(null);

  // Puter.js 동적 로드
  useEffect(()=>{
    if(window.puter){ setPuterReady(true); return; }
    const s = document.createElement("script");
    s.src = "https://js.puter.com/v2/";
    s.onload = () => setPuterReady(true);
    document.head.appendChild(s);
  },[]);

  useEffect(()=>{ bottomRef.current?.scrollIntoView({behavior:"smooth"}); },[msgs,loading]);

  const saveKey = (k) => { setApiKey(k); localStorage.setItem("gemini_key",k); };
  const selectVoice = async (idx) => {
    currentVoiceIdx = idx;
    setSelVoiceIdx(idx);
    localStorage.setItem("puter_voice_idx", idx);
    setShowVoice(false);
    setTtsLoading(true);
    await speak("Hello! I'm your English tutor Seulgi. Nice to meet you!");
    setTtsLoading(false);
  };

  const handleFile = (e) => {
    const file = e.target.files[0]; if(!file) return;
    const reader = new FileReader();
    reader.onload = ev => {
      const b64 = ev.target.result.split(",")[1];
      setPendingImg({b64, mime: file.type});
      setPendingPrev(ev.target.result);
    };
    reader.readAsDataURL(file);
    e.target.value = "";
  };

  // 음성 입력 (Web Speech API - STT) — 연속 인식 + 침묵 감지 자동전송
  const silenceTimer = useRef(null);
  const finalTranscript = useRef("");

  const toggleMic = () => {
    const SR = window.SpeechRecognition || window.webkitSpeechRecognition;
    if (!SR) {
      alert("이 브라우저는 음성 입력을 지원하지 않아요. Chrome을 사용해주세요!");
      return;
    }
    if (listening) {
      // 수동 중단
      clearTimeout(silenceTimer.current);
      recogRef.current?.stop();
      setListening(false);
      return;
    }

    finalTranscript.current = "";
    const recog = new SR();
    recog.lang = "en-US";
    recog.interimResults = true;
    recog.continuous = true;          // 연속 인식 (짧게 끊기지 않음)

    const resetSilence = () => {
      clearTimeout(silenceTimer.current);
      // 5초 침묵 시 자동 종료 → 자동 전송
      silenceTimer.current = setTimeout(() => {
        recog.stop();
      }, 5000);
    };

    recog.onresult = (e) => {
      let interim = "";
      finalTranscript.current = "";
      for (let i=0; i<e.results.length; i++) {
        const t = e.results[i][0].transcript;
        if (e.results[i].isFinal) finalTranscript.current += t;
        else interim += t;
      }
      setInput((finalTranscript.current + interim).trim());
      resetSilence(); // 말할 때마다 타이머 리셋
    };

    recog.onend = () => {
      clearTimeout(silenceTimer.current);
      setListening(false);
      // 말이 끝나면 자동 전송
      const text = finalTranscript.current.trim();
      if (text) {
        setInput(text);
        setTimeout(() => sendVoice(text), 200);
      }
    };
    recog.onerror = () => { clearTimeout(silenceTimer.current); setListening(false); };

    recogRef.current = recog;
    recog.start();
    setListening(true);
    resetSilence();
  };

  const loadSample = () => {
    setPendingImg({b64: SAMPLE_B64, mime:"image/png"});
    setPendingPrev(SAMPLE_PREVIEW);
  };

  // 잘린 응답 이어받기
  const handleContinue = async () => {
    // 마지막 메시지의 cutOff 해제
    setMsgs(prev => prev.map((m,i)=> i===prev.length-1 ? {...m, cutOff:false} : m));
    const contMsg = { role:"user", content:"계속 이어서 진행해주세요." };
    const newMsgs = [...msgs, contMsg];
    setLoading(true);
    try {
      const res = await fetch(
        `https://generativelanguage.googleapis.com/v1beta/models/gemini-2.5-flash:generateContent?key=${apiKey}`,
        { method:"POST", headers:{"Content-Type":"application/json"},
          body: JSON.stringify({
            system_instruction:{ parts:[{ text: SYSTEM_PROMPT }] },
            contents: buildContents(newMsgs, null),
            generationConfig:{ maxOutputTokens:4000 }
          })
        });
      const data = await res.json();
      if (data.error) throw new Error(data.error.message);
      const candidate = data.candidates?.[0];
      const reply = candidate?.content?.parts?.[0]?.text || "계속할 내용이 없어요.";
      const cutOff = candidate?.finishReason === "MAX_TOKENS";
      setMsgs(prev=>[...prev,{role:"assistant",content:reply, cutOff}]);
    } catch(e) {
      setMsgs(prev=>[...prev,{role:"assistant",content:`오류: ${e.message}`}]);
    } finally { setLoading(false); }
  };

  /* Build Gemini contents array */
  const buildContents = (allMsgs, curImg) => {
    return allMsgs.map((m, idx) => {
      const isLast = idx === allMsgs.length - 1;
      const role = m.role === "assistant" ? "model" : "user";
      let imgSrc = null;
      if (m.imagePreview) {
        if (isLast && curImg) imgSrc = curImg;
        else if (storedImg) imgSrc = storedImg;
      }
      if (imgSrc) {
        return { role, parts:[
          { inline_data:{ mime_type: imgSrc.mime, data: imgSrc.b64 }},
          { text: m.content }
        ]};
      }
      return { role, parts:[{ text: m.content }] };
    });
  };

  const sendVoice = (voiceText) => send(voiceText, true);

  const send = async (voiceText, autoSpeak) => {
    const text = (typeof voiceText === "string" ? voiceText : input).trim();
    if (!text && !pendingImg) return;
    if (!apiKey) { setShowKey(true); return; }

    const content = text || "이미지를 업로드했어요. 1단계부터 시작해주세요!";
    const userMsg = { role:"user", content, imagePreview: pendingPrev };
    const newMsgs = [...msgs, userMsg];
    setMsgs(newMsgs); setInput(""); setLoading(true);

    // 4단계 대화 시작 감지
    if (content.includes("4단계")) setConvMode(true);
    // 끝내기 감지
    if (content.includes("끝내기") || content.includes("피드백 주세요") || content.includes("마무리")) setConvMode(false);

    const curImg = pendingImg;
    if (pendingImg) setStoredImg(pendingImg);
    setPendingImg(null); setPendingPrev(null);

    try {
      const apiMsgs = buildContents(newMsgs, curImg);
      const res = await fetch(
        `https://generativelanguage.googleapis.com/v1beta/models/gemini-2.5-flash:generateContent?key=${apiKey}`,
        {
          method:"POST",
          headers:{"Content-Type":"application/json"},
          body: JSON.stringify({
            system_instruction:{ parts:[{ text: SYSTEM_PROMPT }] },
            contents: apiMsgs,
            generationConfig:{ maxOutputTokens:4000 }
          })
        }
      );
      const data = await res.json();
      if (data.error) throw new Error(data.error.message);
      const candidate = data.candidates?.[0];
      let reply = candidate?.content?.parts?.[0]?.text || "다시 시도해주세요.";
      let cutOff = candidate?.finishReason === "MAX_TOKENS";

      // 잘렸으면 자동으로 한 번 이어받아서 합치기
      if (cutOff) {
        const contMsgs = [...newMsgs,
          { role:"assistant", content: reply },
          { role:"user", content:"바로 이어서 계속 작성해주세요. 중복 없이 끊긴 부분부터." }
        ];
        try {
          const res2 = await fetch(
            `https://generativelanguage.googleapis.com/v1beta/models/gemini-2.5-flash:generateContent?key=${apiKey}`,
            { method:"POST", headers:{"Content-Type":"application/json"},
              body: JSON.stringify({
                system_instruction:{ parts:[{ text: SYSTEM_PROMPT }] },
                contents: buildContents(contMsgs, null),
                generationConfig:{ maxOutputTokens:4000 }
              })
            });
          const data2 = await res2.json();
          const cand2 = data2.candidates?.[0];
          const cont = cand2?.content?.parts?.[0]?.text || "";
          reply = reply + cont;
          cutOff = cand2?.finishReason === "MAX_TOKENS"; // 또 잘리면 버튼 표시
        } catch {}
      }

      setMsgs(prev=>[...prev,{role:"assistant",content:reply, cutOff}]);
      // 음성으로 보냈으면 슬기 답변 자동 낭독
      if (autoSpeak) {
        const toRead = extractReadableText(reply);
        if (toRead) speak(toRead);
      }
      // 회화모드에서 응답 후 자동 포커스
      setTimeout(()=>{ inputRef.current?.focus(); }, 100);
    } catch(e) {
      setMsgs(prev=>[...prev,{role:"assistant",content:`오류가 발생했어요 😅\n${e.message}`}]);
    } finally { setLoading(false); }
  };

  const onKey = (e) => { if(e.key==="Enter"&&!e.shiftKey){e.preventDefault();send();} };
  const quickReplies = ["1단계 시작해주세요","2단계로 넘어가요","3단계 시작!","4단계 대화 시작"];

  return (
    <div style={{
      fontFamily:"'Noto Sans KR','Apple SD Gothic Neo',sans-serif",
      background:"#0d0b1a",minHeight:"100vh",
      display:"flex",flexDirection:"column",
      maxWidth:480,margin:"0 auto",overflow:"hidden",
    }}>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Noto+Sans+KR:wght@400;500;700&display=swap');
        *{box-sizing:border-box;margin:0;padding:0;}
        @keyframes bounce{0%,60%,100%{transform:translateY(0)}30%{transform:translateY(-6px)}}
        @keyframes fadeIn{from{opacity:0;transform:translateY(8px)}to{opacity:1;transform:translateY(0)}}
        @keyframes pulse{0%,100%{opacity:1}50%{opacity:0.6}}
        @keyframes glow{0%,100%{box-shadow:0 0 20px rgba(167,139,250,0.3)}50%{box-shadow:0 0 35px rgba(167,139,250,0.6)}}
        ::-webkit-scrollbar{width:4px}::-webkit-scrollbar-thumb{background:rgba(167,139,250,0.3);border-radius:2px}
        textarea{resize:none;outline:none;}textarea::placeholder{color:rgba(167,139,250,0.4);}
        input[type=text]{outline:none;}
        .qbtn{background:rgba(167,139,250,0.1);border:1px solid rgba(167,139,250,0.25);border-radius:20px;color:#c4b5fd;font-size:11px;padding:6px 14px;cursor:pointer;white-space:nowrap;flex-shrink:0;transition:all 0.2s;}
        .qbtn:hover{background:rgba(167,139,250,0.22);}
        .sbtn{background:rgba(52,211,153,0.12);border:1px solid rgba(52,211,153,0.3);border-radius:20px;color:#6ee7b7;font-size:11px;padding:6px 14px;cursor:pointer;flex-shrink:0;}
        .sbtn:hover{background:rgba(52,211,153,0.22);}
        .upload-label{background:rgba(167,139,250,0.15);border:none;border-radius:50%;width:36px;height:36px;display:flex;align-items:center;justify-content:center;cursor:pointer;font-size:17px;flex-shrink:0;transition:background 0.2s;}
        .upload-label:hover{background:rgba(167,139,250,0.3);}
      `}</style>

      {/* BG blobs */}
      <div style={{position:"fixed",top:-100,right:-80,width:300,height:300,borderRadius:"50%",background:"radial-gradient(circle,rgba(124,58,237,0.15),transparent 70%)",pointerEvents:"none"}}/>
      <div style={{position:"fixed",bottom:100,left:-80,width:250,height:250,borderRadius:"50%",background:"radial-gradient(circle,rgba(167,139,250,0.1),transparent 70%)",pointerEvents:"none"}}/>

      {/* Voice picker */}
      {showVoice && (
        <div style={{
          background:"rgba(124,58,237,0.15)",borderBottom:"1px solid rgba(167,139,250,0.3)",
          padding:"12px 16px",
        }}>
          <div style={{fontSize:12,color:"#c4b5fd",marginBottom:8}}>
            🔊 목소리 선택 <span style={{color:"rgba(167,139,250,0.5)",fontSize:10}}>(Gemini TTS · 한국어+영어 동시 지원 · 무료)</span>
          </div>
          {!puterReady && <div style={{fontSize:11,color:"#fcd34d"}}>⏳ Puter.js 로딩 중...</div>}
          {ttsLoading && <div style={{fontSize:11,color:"#6ee7b7"}}>🔊 목소리 테스트 중...</div>}
          <div style={{display:"flex",flexDirection:"column",gap:4}}>
            {PUTER_VOICES.map((v,i)=>(
              <button key={i} onClick={()=>selectVoice(i)}
                disabled={!puterReady || ttsLoading}
                style={{
                  background:selVoiceIdx===i?"rgba(167,139,250,0.35)":"rgba(167,139,250,0.08)",
                  border:`1px solid ${selVoiceIdx===i?"rgba(167,139,250,0.6)":"rgba(167,139,250,0.2)"}`,
                  borderRadius:8,color:"#f1f0ff",
                  fontSize:12,padding:"8px 12px",cursor:"pointer",textAlign:"left",
                  opacity: (!puterReady || ttsLoading) ? 0.5 : 1,
                }}>
                {selVoiceIdx===i ? "✅ " : "   "}{v.label}
              </button>
            ))}
          </div>
          <div style={{fontSize:10,color:"rgba(167,139,250,0.4)",marginTop:8}}>
            선택하면 테스트 음성이 바로 재생돼요
          </div>
        </div>
      )}

      {/* API Key setup banner */}
      {(!apiKey || showKey) && (
        <div style={{
          background:"rgba(245,158,11,0.15)",borderBottom:"1px solid rgba(245,158,11,0.3)",
          padding:"12px 16px",display:"flex",gap:8,alignItems:"center",flexWrap:"wrap",
        }}>
          <span style={{fontSize:12,color:"#fcd34d",flex:"0 0 100%",marginBottom:4}}>🔑 Gemini API 키를 입력해주세요</span>
          <input
            type="text"
            placeholder="AIza..."
            defaultValue={apiKey}
            onBlur={e=>saveKey(e.target.value.trim())}
            style={{
              flex:1,background:"rgba(0,0,0,0.3)",border:"1px solid rgba(245,158,11,0.4)",
              borderRadius:8,padding:"6px 10px",color:"#fff",fontSize:12,minWidth:0,
            }}
          />
          <button onClick={()=>setShowKey(false)}
            style={{background:"rgba(245,158,11,0.3)",border:"none",borderRadius:8,color:"#fcd34d",padding:"6px 12px",cursor:"pointer",fontSize:12}}>
            저장
          </button>
        </div>
      )}

      {/* Header */}
      <div style={{
        padding:"14px 18px",
        background:"rgba(13,11,26,0.95)",borderBottom:"1px solid rgba(167,139,250,0.15)",
        backdropFilter:"blur(20px)",display:"flex",alignItems:"center",gap:12,
        position:"sticky",top:0,zIndex:10,
      }}>
        <div style={{
          width:42,height:42,borderRadius:"50%",flexShrink:0,
          background:"linear-gradient(135deg,#7c3aed,#c084fc)",
          display:"flex",alignItems:"center",justifyContent:"center",fontSize:20,
          animation:"glow 3s ease-in-out infinite",
        }}>🌸</div>
        <div style={{flex:1}}>
          <div style={{fontWeight:700,fontSize:15,color:"#f1f0ff"}}>영어학습</div>
          <div style={{fontSize:11,color:"#a78bfa",display:"flex",alignItems:"center",gap:5}}>
            <span style={{width:6,height:6,borderRadius:"50%",background: puterReady ? "#34d399" : "#fbbf24",display:"inline-block",animation:"pulse 2s infinite"}}/>
            슬기 선생님 · {puterReady ? "Gemini TTS 준비됨 🇰🇷🇺🇸" : "목소리 로딩 중..."}
          </div>
        </div>
        <div style={{display:"flex",gap:6}}>
          <button onClick={()=>setShowVoice(v=>!v)}
            style={{background:"rgba(167,139,250,0.1)",border:"1px solid rgba(167,139,250,0.2)",borderRadius:8,color:"#a78bfa",fontSize:11,padding:"5px 10px",cursor:"pointer"}}>
            🔊 목소리
          </button>
          <button onClick={()=>setShowKey(v=>!v)}
            style={{background:"rgba(167,139,250,0.1)",border:"1px solid rgba(167,139,250,0.2)",borderRadius:8,color:"#a78bfa",fontSize:11,padding:"5px 10px",cursor:"pointer"}}>
            🔑 API
          </button>
        </div>
      </div>

      {/* Step strip */}
      <div style={{display:"flex",padding:"6px 20px",background:"rgba(255,255,255,0.02)",borderBottom:"1px solid rgba(167,139,250,0.08)"}}>
        {["1️⃣ 낭독","2️⃣ 어휘","3️⃣ 표현","4️⃣ 대화"].map((s,i)=>(
          <div key={i} style={{flex:1,textAlign:"center",fontSize:10,color:"rgba(167,139,250,0.5)",
            borderRight:i<3?"1px solid rgba(167,139,250,0.1)":"none",padding:"2px 0"}}>{s}</div>
        ))}
      </div>

      {/* Messages */}
      <div style={{flex:1,overflowY:"auto",padding:"18px 14px 8px"}}>
        {msgs.map((m,i)=><Bubble key={i} msg={m} onContinue={i===msgs.length-1 ? handleContinue : null}/>)}
        {loading && (
          <div style={{display:"flex",alignItems:"flex-end",gap:10,marginBottom:16}}>
            <div style={{width:36,height:36,borderRadius:"50%",background:"linear-gradient(135deg,#7c3aed,#a78bfa)",display:"flex",alignItems:"center",justifyContent:"center",fontSize:16,flexShrink:0}}>🌸</div>
            <div style={{background:"rgba(255,255,255,0.06)",border:"1px solid rgba(167,139,250,0.2)",borderRadius:"18px 18px 18px 4px"}}>
              <Dots/>
            </div>
          </div>
        )}
        <div ref={bottomRef}/>
      </div>

      {/* Conversation mode banner */}
      {convMode && (
        <div style={{
          margin:"4px 14px 0",padding:"8px 14px",
          background:"linear-gradient(90deg,rgba(52,211,153,0.12),rgba(167,139,250,0.12))",
          border:"1px solid rgba(52,211,153,0.3)",
          borderRadius:10,display:"flex",alignItems:"center",justifyContent:"space-between",
        }}>
          <span style={{fontSize:12,color:"#6ee7b7"}}>💬 자유 회화 모드 — Enter로 빠른 전송</span>
          <button
            onClick={()=>{ setInput("끝내기"); setTimeout(()=>send(),50); }}
            style={{background:"rgba(52,211,153,0.2)",border:"1px solid rgba(52,211,153,0.4)",
              borderRadius:8,color:"#6ee7b7",fontSize:11,padding:"4px 10px",cursor:"pointer"}}>
            🏁 대화 끝내기
          </button>
        </div>
      )}

      {/* Sample button */}
      <div style={{padding:"6px 14px 2px"}}>
        <button className="sbtn" onClick={loadSample}
          style={{width:"100%",padding:"9px 0",fontSize:13,fontWeight:600,borderRadius:12}}>
          🧪 샘플 이미지로 바로 시작하기
        </button>
      </div>

      {/* Quick replies — hidden in convMode */}
      {!convMode && (
        <div style={{display:"flex",gap:8,padding:"4px 14px 6px",overflowX:"auto"}}>
          {quickReplies.map((q,i)=>(
            <button key={i} className="qbtn" onClick={()=>{setInput(q);inputRef.current?.focus();}}>{q}</button>
          ))}
        </div>
      )}

      {/* Pending preview */}
      {pendingPrev && (
        <div style={{
          margin:"0 14px 6px",padding:"10px",
          background:"rgba(124,58,237,0.15)",border:"1px solid rgba(167,139,250,0.3)",
          borderRadius:12,display:"flex",alignItems:"center",gap:10,
        }}>
          <img src={pendingPrev} alt="prev" style={{height:44,width:44,objectFit:"cover",borderRadius:8}}/>
          <div style={{flex:1,fontSize:12,color:"#c4b5fd"}}>이미지 준비 완료 ✅<br/>전송하면 학습 시작!</div>
          <button onClick={()=>{setPendingImg(null);setPendingPrev(null);}}
            style={{background:"none",border:"none",color:"#f87171",cursor:"pointer",fontSize:18}}>×</button>
        </div>
      )}

      {/* Listening banner */}
      {listening && (
        <div style={{
          margin:"0 14px 6px",padding:"8px 14px",
          background:"rgba(239,68,68,0.15)",border:"1px solid rgba(239,68,68,0.3)",
          borderRadius:10,display:"flex",alignItems:"center",gap:8,
        }}>
          <span style={{width:8,height:8,borderRadius:"50%",background:"#ef4444",display:"inline-block",animation:"pulse 1s infinite"}}/>
          <span style={{fontSize:12,color:"#fca5a5"}}>🎤 듣는 중... 말이 끝나고 5초 지나면 자동 전송돼요</span>
        </div>
      )}

      {/* Input bar */}
      <div style={{padding:"10px 14px 18px",background:"rgba(13,11,26,0.97)",borderTop:"1px solid rgba(167,139,250,0.12)",backdropFilter:"blur(20px)"}}>
        <div style={{
          display:"flex",gap:8,alignItems:"flex-end",
          background:"rgba(255,255,255,0.05)",
          border:"1px solid rgba(167,139,250,0.25)",
          borderRadius:24,padding:"8px 8px 8px 14px",
        }}>
          <label htmlFor="file-upload" className="upload-label" title="이미지 업로드">📎</label>
          <input id="file-upload" type="file" accept="image/*" onChange={handleFile} style={{display:"none"}} ref={fileRef}/>

          <textarea
            ref={inputRef}
            value={input}
            onChange={e=>setInput(e.target.value)}
            onKeyDown={onKey}
            placeholder="메시지 입력 또는 이미지 업로드..."
            rows={1}
            style={{
              flex:1,background:"transparent",border:"none",
              color:"#f1f0ff",fontSize:14,lineHeight:1.5,
              maxHeight:100,overflow:"auto",fontFamily:"inherit",
            }}
            onInput={e=>{e.target.style.height="auto";e.target.style.height=Math.min(e.target.scrollHeight,100)+"px";}}
          />
          <button onClick={toggleMic}
            title={listening ? "듣는 중... (5초 침묵 시 자동 전송)" : "음성 입력 (영어로 말하기)"}
            style={{
              background: listening ? "rgba(239,68,68,0.3)" : "rgba(167,139,250,0.15)",
              border: listening ? "1px solid rgba(239,68,68,0.5)" : "none",
              borderRadius:"50%",width:36,height:36,
              display:"flex",alignItems:"center",justifyContent:"center",
              fontSize:15,cursor:"pointer",flexShrink:0,
              animation: listening ? "pulse 1s infinite" : "none",
            }}
          >{listening ? "🔴" : "🎤"}</button>
          <button onClick={send}
            disabled={loading||(!input.trim()&&!pendingImg)}
            style={{
              background:loading||(!input.trim()&&!pendingImg)?"rgba(167,139,250,0.2)":"linear-gradient(135deg,#7c3aed,#a78bfa)",
              border:"none",borderRadius:"50%",width:36,height:36,
              display:"flex",alignItems:"center",justifyContent:"center",
              fontSize:15,cursor:loading||(!input.trim()&&!pendingImg)?"not-allowed":"pointer",
              flexShrink:0,
              boxShadow:loading||(!input.trim()&&!pendingImg)?"none":"0 0 12px rgba(124,58,237,0.4)",
              color:"#fff",
            }}
          >{loading?"⏳":"➤"}</button>
        </div>
        <div style={{textAlign:"center",fontSize:10,color:"rgba(167,139,250,0.3)",marginTop:6}}>
          🎤 음성 입력 · 🔊 낭독 · 🧪 샘플 · Enter 전송
        </div>
      </div>
    </div>
  );
}